const suppressViewTransitionRejections=i=>{const e=()=>{};i.ready.catch(e),i.finished.catch(e)};window.addEventListener("pagereveal",i=>{if(i.viewTransition){const e="default";suppressViewTransitionRejections(i.viewTransition),i.viewTransition.types.add(e)}});